const rows = $input.all().map(item => item.json);

const pending = rows.filter(r =>
  String(r.status || "").toLowerCase().trim() === "pending"
);

if (pending.length === 0) {
  throw new Error("No pending course topics in the sheet -- add more rows or this run has nothing to do.");
}

pending.sort((a, b) => {
  const courseCompare = String(a.course_name || "").localeCompare(String(b.course_name || ""));
  if (courseCompare !== 0) return courseCompare;
  return Number(a.sequence_number || 0) - Number(b.sequence_number || 0);
});

const next = pending[0];

function numberToWords(num) {
  num = Number(num);
  if (!Number.isFinite(num)) return "";
  if (num === 0) return "zero";
  if (num < 0) return "negative " + numberToWords(Math.abs(num));

  const ones = ["","one","two","three","four","five","six","seven","eight","nine","ten","eleven","twelve","thirteen","fourteen","fifteen","sixteen","seventeen","eighteen","nineteen"];
  const tens = ["","","twenty","thirty","forty","fifty","sixty","seventy","eighty","ninety"];

  function underThousand(n) {
    let words = [];
    if (n >= 100) { words.push(ones[Math.floor(n / 100)]); words.push("hundred"); n %= 100; }
    if (n >= 20) { words.push(tens[Math.floor(n / 10)]); n %= 10; }
    if (n > 0) words.push(ones[n]);
    return words.join(" ");
  }

  const scales = [
    { value: 1000000000, name: "billion" },
    { value: 1000000, name: "million" },
    { value: 1000, name: "thousand" }
  ];

  let words = [];
  for (const scale of scales) {
    const count = Math.floor(num / scale.value);
    if (count > 0) { words.push(numberToWords(count)); words.push(scale.name); num %= scale.value; }
  }
  if (num > 0) words.push(underThousand(num));
  return words.join(" ").replace(/\s+/g, " ").trim();
}

function decimalToWords(rawNumber) {
  const clean = String(rawNumber).replace(/,/g, "").trim();
  if (!clean.includes(".")) return numberToWords(Number(clean));

  const digitWords = {"0":"zero","1":"one","2":"two","3":"three","4":"four","5":"five","6":"six","7":"seven","8":"eight","9":"nine"};
  const [wholeRaw, decimalRaw] = clean.split(".");
  const wholeWords = numberToWords(Number(wholeRaw || "0"));
  const decimalWords = decimalRaw.split("").map(d => digitWords[d] || "").filter(Boolean).join(" ");
  return `${wholeWords} point ${decimalWords}`.trim();
}

function replaceNumbersInText(text) {
  return String(text || "").replace(/\$?\d[\d,]*(\.\d+)?%?/g, match => {
    const hasDollar = match.includes("$");
    const hasPercent = match.includes("%");
    const clean = match.replace(/[$,%]/g, "");
    let words = decimalToWords(clean);
    if (hasDollar) words += " dollars";
    if (hasPercent) words += " percent";
    return words.trim();
  });
}

function normalizeFinanceSpeechText(text) {
  let value = String(text || "");
  value = value.replace(/\b401\s*\(?k\)?(?![a-z0-9])/gi, "four oh one kay");
  value = value.replace(/\b50\s*\/\s*30\s*\/\s*20\b/g, "fifty thirty twenty");
  value = value.replace(/\b(\d+)\s*[-–—]\s*(\d+)\b/g, (_, start, end) => `${numberToWords(start)} to ${numberToWords(end)}`);
  return replaceNumbersInText(value);
}

const courseName = normalizeFinanceSpeechText(next.course_name);
const topicTitle = normalizeFinanceSpeechText(next.topic_title);
const sequenceWords = numberToWords(next.sequence_number);

const sameCourseRows = rows
  .filter(r => String(r.course_name || "").trim() === String(next.course_name || "").trim())
  .sort((a, b) => Number(a.sequence_number || 0) - Number(b.sequence_number || 0));

const currentCourseIndex = sameCourseRows.findIndex(r =>
  String(r.row_number || "") === String(next.row_number || "") ||
  Number(r.sequence_number || 0) === Number(next.sequence_number || 0)
);

const followingTopic = currentCourseIndex >= 0 ? sameCourseRows[currentCourseIndex + 1] : null;
const nextTopicTitle = followingTopic ? normalizeFinanceSpeechText(followingTopic.topic_title) : "";

const ctaInstruction = nextTopicTitle
  ? `Close with a single sentence that makes the next lesson feel like the unavoidable next step. The next lesson is "${nextTopicTitle}". Name it directly and make it sound useful, not like a course announcement.`
  : `Close with a single sentence inviting the listener to continue the course. Do not invent a next topic.`;

const video_prompt = `
Write a complete spoken finance narration for the following topic.

Course: "${courseName}"
Lesson: entry ${sequenceWords}, "${topicTitle}"

Output only the spoken narration. No markdown, no bullets, no headings, no symbols, no digits.

Every number must be written as spoken words. Every dollar amount, percentage, timeframe, and figure must be written exactly as a human would say it aloud.

==============================
LENGTH
==============================
Write between one thousand five hundred and one thousand 800 hundred words maximum.
Do not exceed two thousand words under any circumstances.
Each paragraph must make one clear point with at least three sentences.

==============================
HOW TO OPEN
==============================

The opening four sentences must follow this exact pattern.

Sentence one: a cold statement of a real financial consequence that happens to people who ignore this topic. State it as a fact, not a question, not a setup. Make it specific enough that someone who has experienced it would recognize it instantly.

Good examples of sentence one:
"Running out of money three days before payday is not a cash flow problem, it is a savings problem most people refuse to name."
"The reason debt keeps coming back for people who pay it off is not bad luck, it is the absence of a buffer between income and emergencies."
"Losing a job with no savings does not give you time to think, it gives you about eleven days before the first bill goes unpaid."

Sentence two: name the exact behavior or assumption that causes the problem in sentence one. Be specific about what people do wrong, not vague.

Sentence three: name what is actually happening financially because of that behavior, in concrete terms.

Sentence four: open a tension loop by describing a situation the viewer can picture themselves in, where the problem from sentence one is quietly building before they notice it.

After sentence four, transition into teaching the concept clearly without announcing that you are doing so.

==============================
HOW TO TEACH
==============================

Teach the concept directly after the opening four sentences.

Use one real-life example if it makes the concept clearer. One is enough.

Show the most common beginner mistake with this topic.

Explain what the mistake costs in practical terms, not emotional terms.

Give a correction. Make it specific and actionable.

Connect this topic to the next financial decision the viewer will face.

Vary the approach paragraph by paragraph. Some paragraphs explain. Some show consequences. Some name a mistake. Some give a correction. Some connect to a broader pattern.

==============================
NUMBER PACING
==============================

Use spoken figures only when they make a point more concrete.
Most lessons need no more than six figures total.
After any paragraph containing a figure, write at least one paragraph with no figure before the next one.
Never put two figures in the same paragraph.

==============================
HOW TO CLOSE
==============================

The second to last paragraph summarizes the single most important shift in thinking this lesson creates. No recap of figures. One clear takeaway about behavior or understanding.

${ctaInstruction}

==============================
STYLE
==============================

Write the way a sharp person explains something clearly to a friend who made a financial mistake. Direct. Concrete. No theatrics. No filler phrases. No repeated sentence structure. Vary the rhythm. Some sentences short. Some longer when the idea needs it.
`.trim();

