  value = value.replace(/\b(\d+)\s*x\s*(\d+)\b/g, (_, a, b) => {
    return `${numberToWords(Number(a))} by ${numberToWords(Number(b))}`;
  });

  value = value.replace(/\b(\d+)\s*[-–—]\s*(\d+)\b/g, (_, start, end) => {
    return `${numberToWords(start)} to ${numberToWords(end)}`;
  });

  return replaceNumbersInText(value);
}

