const videos = $input.all();
let latestDate = null;

for (const item of videos) {
  const candidates = [
    item.json.status?.publishAt,
    item.json.snippet?.publishTime,
    item.json.snippet?.publishedAt,
  ].filter(Boolean);

  for (const pt of candidates) {
    const d = new Date(pt);
    if (!isNaN(d) && (!latestDate || d > latestDate)) {
      latestDate = d;
    }
  }
}

if (!latestDate) {
  latestDate = new Date();
}

// Find next Tuesday or Friday from latest date
const next = new Date(latestDate);
next.setUTCHours(16, 0, 0, 0); // 12am PH = 4pm UTC

const day = next.getUTCDay();
let daysToAdd;
if (day === 2) {
  daysToAdd = 3; // Tuesday to Friday
} else if (day === 5) {
  daysToAdd = 4; // Friday to Tuesday
} else {
  const daysToTue = (2 - day + 7) % 7 || 7;
  const daysToFri = (5 - day + 7) % 7 || 7;
  daysToAdd = Math.min(daysToTue, daysToFri);
}
next.setDate(next.getDate() + daysToAdd);

// Safety: never schedule in the past or onto the same slot as latestDate
const now = new Date();
while (next <= now || next.getTime() === latestDate.getTime()) {
  next.setDate(next.getDate() + (next.getUTCDay() === 2 ? 3 : 4));
}

const scheduledDate = next.toISOString();
return [{ json: { scheduledDate } }];

